import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { api } from '../contexts/AuthContext';
import { useAuth } from '../contexts/AuthContext';
import ConfirmDialog from '../components/ConfirmDialog';

const VideoDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAdmin } = useAuth();
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [urlRefreshed, setUrlRefreshed] = useState(false);
  const [refreshTimestamp, setRefreshTimestamp] = useState(null);
  const [refreshLoading, setRefreshLoading] = useState(false);
  const videoRef = useRef(null);
  const hlsRef = useRef(null);
  const [confirmDialog, setConfirmDialog] = useState({
    isOpen: false,
    type: 'danger',
    title: '',
    message: '',
    onConfirm: null
  });
  const [relatedVideos, setRelatedVideos] = useState([]);
  const [relatedLoading, setRelatedLoading] = useState(true);
  const [hoveredRelatedVideo, setHoveredRelatedVideo] = useState(null);

  useEffect(() => {
    fetchVideoDetail();
  }, [id]);

  // Auto-play video when video data is loaded
  useEffect(() => {
    if (video && !isPlaying) {
      setIsPlaying(true);
    }
  }, [video]);

  // HLS.js player for scraped m3u8 videos
  useEffect(() => {
    if (!isPlaying || !video?.is_scraped || !videoRef.current) return;
    const videoUrl = video.video_url || video.source_url;
    if (!videoUrl) return;

    const initHls = (Hls) => {
      if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; }
      if (Hls.isSupported()) {
        const hls = new Hls({ enableWorker: true });
        hlsRef.current = hls;
        hls.loadSource(videoUrl);
        hls.attachMedia(videoRef.current);
        hls.on(Hls.Events.MANIFEST_PARSED, () => videoRef.current?.play().catch(() => {}));
      } else if (videoRef.current.canPlayType('application/vnd.apple.mpegurl')) {
        videoRef.current.src = videoUrl;
        videoRef.current.play().catch(() => {});
      }
    };

    if (window.Hls) {
      initHls(window.Hls);
    } else {
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/hls.js@latest/dist/hls.min.js';
      s.onload = () => initHls(window.Hls);
      document.head.appendChild(s);
    }

    return () => { if (hlsRef.current) { hlsRef.current.destroy(); hlsRef.current = null; } };
  }, [isPlaying, video]);

  const fetchVideoDetail = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await api.get(`/video/detail/${id}`);
      setVideo(response.data.video);
      setUrlRefreshed(response.data.url_refreshed || false);
      setRefreshTimestamp(response.data.refresh_timestamp || null);

      fetchRelatedVideos(response.data.video);
    } catch (err) {
      console.error('Error fetching video detail:', err);
      setError('获取视频信息失败');
    } finally {
      setLoading(false);
    }
  };

  const fetchRelatedVideos = async (currentVideo) => {
    setRelatedLoading(true);
    try {
      // 基于当前视频的标签获取相关视频
      const response = await api.get('/video/list', {
        params: {
          per_page: 8,
          search: currentVideo.tags && currentVideo.tags.length > 0 ? currentVideo.tags[0] : ''
        }
      });

      // 过滤掉当前视频
      const filteredVideos = response.data.videos.filter(v => v.id !== currentVideo.id);
      setRelatedVideos(filteredVideos.slice(0, 6)); // 最多显示6个相关视频
    } catch (err) {
      console.error('Error fetching related videos:', err);
      setRelatedVideos([]);
    } finally {
      setRelatedLoading(false);
    }
  };

  const formatDuration = (seconds) => {
    if (!seconds) return '00:00';
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const formatViews = (views) => {
    if (views >= 1000000) {
      return `${(views / 1000000).toFixed(1)}M`;
    } else if (views >= 1000) {
      return `${(views / 1000).toFixed(1)}K`;
    }
    return views.toString();
  };

  const handleApprove = () => {
    setConfirmDialog({
      isOpen: true,
      type: 'info',
      title: '审核通过',
      message: '确定要通过这个视频的审核吗？通过后视频将对所有用户可见。',
      onConfirm: async () => {
        try {
          await api.put(`/admin/videos/${video.id}`, { status: 'approved' });
          setVideo({ ...video, status: 'approved' });
          alert('视频已通过审核');
        } catch (error) {
          console.error('Error approving video:', error);
          alert('操作失败，请重试');
        }
        setConfirmDialog({ ...confirmDialog, isOpen: false });
      }
    });
  };

  const handleReject = () => {
    setConfirmDialog({
      isOpen: true,
      type: 'danger',
      title: '拒绝视频',
      message: '确定要拒绝这个视频吗？拒绝后视频将被隐藏。',
      onConfirm: async () => {
        try {
          await api.put(`/admin/videos/${video.id}`, { status: 'rejected' });
          setVideo({ ...video, status: 'rejected' });
          alert('视频已拒绝');
        } catch (error) {
          console.error('Error rejecting video:', error);
          alert('操作失败，请重试');
        }
        setConfirmDialog({ ...confirmDialog, isOpen: false });
      }
    });
  };

  const handleRefreshUrl = async () => {
    if (!video || refreshLoading) return;

    console.log('Starting URL refresh for video ID:', video.id);
    setRefreshLoading(true);
    try {
      const response = await api.get(`/video/detail/${video.id}`);
      console.log('URL refresh response:', response.data);

      const updatedVideo = response.data.video;
      setVideo(updatedVideo);
      setUrlRefreshed(response.data.url_refreshed || false);
      setRefreshTimestamp(response.data.refresh_timestamp || null);

      // 如果URL被刷新了，显示成功消息
      if (response.data.url_refreshed) {
        console.log('Video URL successfully refreshed');
        alert('视频URL已成功刷新！');
      } else {
        console.log('Video URL did not change, no refresh needed');
        alert('视频URL未发生变化，无需刷新。');
      }
    } catch (err) {
      console.error('Error refreshing video URL:', err);
      alert('刷新视频URL失败，请重试。');
    } finally {
      setRefreshLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    const styles = {
      pending: 'bg-yellow-100 text-yellow-800',
      approved: 'bg-green-100 text-green-800',
      rejected: 'bg-red-100 text-red-800'
    };

    const labels = {
      pending: '待审核',
      approved: '已通过',
      rejected: '已拒绝'
    };

    return (
      <span className={`px-3 py-1 text-sm font-medium rounded-full ${styles[status] || 'bg-gray-100 text-gray-800'}`}>
        {labels[status] || status}
      </span>
    );
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (error || !video) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">{error || '视频未找到'}</h2>
          <button
            onClick={() => navigate('/')}
            className="bg-primary-600 text-white px-6 py-2 rounded-lg hover:bg-primary-700 transition-colors"
          >
            返回首页
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Video Player */}
          <div className="lg:col-span-2">
            {/* Video Player */}
            <div className="bg-black rounded-xl overflow-hidden aspect-video relative">
              {/* URL Refresh Status */}
              {urlRefreshed && (
                <div className="absolute top-4 left-4 z-10 bg-green-500 text-white px-3 py-1 rounded-lg text-sm flex items-center space-x-2 animate-pulse">
                  <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                  </svg>
                  <span>视频URL已刷新</span>
                  {refreshTimestamp && (
                    <span className="text-xs opacity-75">
                      {new Date(refreshTimestamp).toLocaleTimeString()}
                    </span>
                  )}
                </div>
              )}

              {/* Refresh Loading Indicator */}
              {refreshLoading && (
                <div className="absolute top-4 left-4 z-10 bg-blue-500 text-white px-3 py-1 rounded-lg text-sm flex items-center space-x-2">
                  <svg className="w-4 h-4 animate-spin" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" />
                  </svg>
                  <span>正在刷新视频URL...</span>
                </div>
              )}

              {isPlaying ? (
                video.is_scraped ? (
                  // 抓取视频用 HLS.js 播放 m3u8
                  <video
                    ref={videoRef}
                    controls
                    muted
                    className="w-full h-full object-contain"
                    crossOrigin="anonymous"
                  />
                ) : (
                  // 本地视频使用video标签
                  <video
                    controls
                    autoPlay
                    className="w-full h-full object-contain"
                    onEnded={() => setIsPlaying(false)}
                    src={video.video_url || video.source_url}
                  >
                    您的浏览器不支持视频播放。
                  </video>
                )
              ) : (
                <div className="relative w-full h-full">
                  {video.cover_image ? (
                    <img
                      src={video.is_scraped ? video.cover_image : `http://localhost:5000/api/video/cover/${video.id}`}
                      alt={video.title}
                      className="w-full h-full object-cover"
                      onError={(e) => {
                        // 如果封面加载失败，显示默认占位符
                        e.target.style.display = 'none';
                        e.target.parentElement.innerHTML = `
                          <div class="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                            <svg class="w-20 h-20 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                              <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                            </svg>
                          </div>
                        `;
                      }}
                    />
                  ) : (
                    <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                      <svg className="w-20 h-20 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                        <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                      </svg>
                    </div>
                  )}

                  {/* Play Button Overlay */}
                  <button
                    onClick={() => setIsPlaying(true)}
                    className="absolute inset-0 flex items-center justify-center bg-black/30 hover:bg-black/40 transition-colors group"
                  >
                    <div className="w-20 h-20 bg-white/90 rounded-full flex items-center justify-center transform group-hover:scale-110 transition-transform">
                      <svg className="w-10 h-10 text-primary-600 ml-1" fill="currentColor" viewBox="0 0 20 20">
                        <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                      </svg>
                    </div>
                  </button>
                </div>
              )}
            </div>

            {/* Video Info */}
            <div className="bg-white rounded-xl shadow-sm mt-6 p-6">
              <div className="flex items-center justify-between mb-4">
                <h1 className="text-2xl font-bold text-gray-900">{video.title}</h1>
                <div className="flex items-center space-x-3">
                  {video.status === 'pending' && getStatusBadge(video.status)}
                  {video.is_scraped && (
                    <button
                      onClick={handleRefreshUrl}
                      disabled={refreshLoading}
                      className="bg-blue-500 hover:bg-blue-600 text-white px-3 py-1 rounded-lg text-sm flex items-center space-x-1 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 010 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-11.601-2.566 1 1 0 01.61-1.276z" clipRule="evenodd" />
                      </svg>
                      <span>刷新URL</span>
                    </button>
                  )}
                </div>
              </div>

              <div className="flex items-center text-sm text-gray-500 space-x-4 mb-4">
                <span>{formatViews(video.view_count)} 次观看</span>
                <span>•</span>
                <span>{new Date(video.created_at).toLocaleDateString()}</span>
                <span>•</span>
                <span>{formatDuration(video.duration)}</span>
              </div>

              {/* Admin Actions */}
              {isAdmin() && video.status === 'pending' && (
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6">
                  <h3 className="text-sm font-medium text-blue-800 mb-3">管理员审核操作</h3>
                  <div className="flex space-x-3">
                    <button
                      onClick={handleApprove}
                      className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-green-700 transition-colors"
                    >
                      通过审核
                    </button>
                    <button
                      onClick={handleReject}
                      className="bg-red-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-red-700 transition-colors"
                    >
                      拒绝视频
                    </button>
                  </div>
                </div>
              )}

              <div className="flex items-center space-x-3 mb-6 pb-6 border-b border-gray-100">
                <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center">
                  <span className="text-lg font-medium text-primary-700">
                    {video.author?.charAt(0).toUpperCase() || 'U'}
                  </span>
                </div>
                <div>
                  <p className="font-medium text-gray-900">{video.author || '未知用户'}</p>
                </div>
              </div>

              {video.description && (
                <div className="prose max-w-none">
                  <h3 className="text-lg font-semibold text-gray-900 mb-2">视频简介</h3>
                  <p className="text-gray-600 whitespace-pre-wrap">{video.description}</p>
                </div>
              )}

              {video.tags && video.tags.length > 0 && (
                <div className="mt-4">
                  <div className="flex flex-wrap gap-2">
                    {video.tags.map((tag, index) => (
                      <span
                        key={index}
                        className="px-3 py-1 bg-gray-100 text-gray-600 text-sm rounded-full"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Sidebar */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-xl shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">相关推荐</h3>

              {relatedLoading ? (
                <div className="space-y-3">
                  {[...Array(3)].map((_, i) => (
                    <div key={i} className="animate-pulse">
                      <div className="flex space-x-3">
                        <div className="w-32 h-20 bg-gray-200 rounded"></div>
                        <div className="flex-1 space-y-2">
                          <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                          <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              ) : relatedVideos.length > 0 ? (
                <div className="space-y-4">
                  {relatedVideos.map((relatedVideo) => (
                    <Link
                      key={relatedVideo.id}
                      to={`/video/${relatedVideo.id}`}
                      className="flex space-x-3 group cursor-pointer"
                    >
                      <div 
                        className="w-32 h-20 rounded overflow-hidden flex-shrink-0 relative"
                        onMouseEnter={() => setHoveredRelatedVideo(relatedVideo.id)}
                        onMouseLeave={() => setHoveredRelatedVideo(null)}
                      >
                        {hoveredRelatedVideo === relatedVideo.id ? (
                          <video
                            src={relatedVideo.video_url}
                            autoPlay
                            muted
                            loop
                            className="w-full h-full object-cover"
                          />
                        ) : relatedVideo.cover_image ? (
                          <img
                            src={`http://localhost:5000/api/video/cover/${relatedVideo.id}`}
                            alt={relatedVideo.title}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center">
                            <svg className="w-6 h-6 text-white/50" fill="currentColor" viewBox="0 0 20 20">
                              <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                            </svg>
                          </div>
                        )}
                        {/* Duration Badge - 只在未悬浮时显示 */}
                        {hoveredRelatedVideo !== relatedVideo.id && (
                          <div className="absolute bottom-1 right-1 bg-black/70 text-white text-xs px-1 py-0.5 rounded">
                            {formatDuration(relatedVideo.duration)}
                          </div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <h4 className="text-sm font-medium text-gray-900 line-clamp-2 group-hover:text-primary-600 transition-colors">
                          {relatedVideo.title}
                        </h4>
                        <p className="text-xs text-gray-500 mt-1">{relatedVideo.author}</p>
                        <p className="text-xs text-gray-400 mt-1">
                          {formatViews(relatedVideo.view_count)} 次观看
                        </p>
                      </div>
                    </Link>
                  ))}
                </div>
              ) : (
                <p className="text-gray-500 text-sm">暂无相关推荐视频</p>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Confirm Dialog */}
      <ConfirmDialog
        isOpen={confirmDialog.isOpen}
        onClose={() => setConfirmDialog({ ...confirmDialog, isOpen: false })}
        onConfirm={confirmDialog.onConfirm}
        title={confirmDialog.title}
        message={confirmDialog.message}
        type={confirmDialog.type}
        confirmText="确认"
        cancelText="取消"
      />
    </div>
  );
};

export default VideoDetail;
